import jwt from 'jsonwebtoken';

export default function handler(req, res) {
  if (req.method !== 'GET') return res.status(405).end();

  const runId = process.env.ZEALT_RUN_ID || 'default-run';
  const rawEmail = process.env.MAGICBELL_EMAIL || 'test@example.com';

  let userEmail = rawEmail;
  if (rawEmail.includes('@')) {
    const [local, domain] = rawEmail.split('@');
    userEmail = `${local}+${runId}@${domain}`;
  } else {
    userEmail = `${rawEmail}+${runId}`;
  }

  const secretKey = process.env.MAGICBELL_SECRET_KEY;
  if (!secretKey) {
    return res.status(500).json({ error: 'Missing MAGICBELL_SECRET_KEY' });
  }

  // Generate User JWT
  const userJwt = jwt.sign({ user_email: userEmail }, secretKey, {
    expiresIn: '1h',
  });

  res.status(200).json({
    userEmail,
    userJwt,
    apiKey: process.env.MAGICBELL_API_KEY,
  });
}

export default async function handler(req, res) {
  if (req.method !== 'POST') return res.status(405).end();

  const runId = process.env.ZEALT_RUN_ID || 'default-run';
  const rawEmail = process.env.MAGICBELL_EMAIL || 'test@example.com';

  let userEmail = rawEmail;
  if (rawEmail.includes('@')) {
    const [local, domain] = rawEmail.split('@');
    userEmail = `${local}+${runId}@${domain}`;
  } else {
    userEmail = `${rawEmail}+${runId}`;
  }

  const apiKey = process.env.MAGICBELL_API_KEY;
  const secretKey = process.env.MAGICBELL_SECRET_KEY;

  if (!apiKey || !secretKey) {
    return res.status(500).json({ error: 'Missing MagicBell credentials' });
  }

  try {
    const response = await fetch('https://api.magicbell.com/broadcasts', {
      method: 'POST',
      headers: {
        'X-MAGICBELL-API-KEY': apiKey,
        'X-MAGICBELL-API-SECRET': secretKey,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        broadcast: {
          title: 'Test Broadcast Notification',
          text: 'This is a test notification to verify the unread badge count.',
          recipients: [{ email: userEmail }],
        },
      }),
    });

    if (!response.ok) {
      const errorText = await response.text();
      console.error('MagicBell API Error:', errorText);
      return res.status(response.status).json({ error: 'Failed to broadcast', details: errorText });
    }

    const data = await response.json();
    return res.status(200).json({ success: true, data });
  } catch (err) {
    console.error('Broadcast error:', err);
    return res.status(500).json({ error: 'Internal server error' });
  }
}

import { useEffect, useState } from 'react';
import { MagicBellProvider, FloatingInbox } from '@magicbell/react';
import '@magicbell/react/dist/index.css';

export default function Home() {
  const [config, setConfig] = useState(null);

  useEffect(() => {
    fetch('/api/config')
      .then((res) => res.json())
      .then((data) => setConfig(data))
      .catch((err) => console.error('Failed to fetch config', err));
  }, []);

  const triggerBroadcast = async () => {
    try {
      const res = await fetch('/api/broadcast', { method: 'POST' });
      const data = await res.json();
      console.log('Broadcast response:', data);
    } catch (err) {
      console.error('Failed to trigger broadcast', err);
    }
  };

  if (!config) {
    return <div>Loading MagicBell config...</div>;
  }

  const tabs = [
    { id: 'unread', title: 'Unread', storeId: 'unread' },
    { id: 'all', title: 'All', storeId: 'default' }
  ];

  return (
    <div style={{ padding: '2rem', fontFamily: 'sans-serif' }}>
      <h1>MagicBell Custom Tabs Test</h1>
      <button onClick={triggerBroadcast} style={{ marginBottom: '1rem', padding: '0.5rem 1rem' }}>
        Send Broadcast
      </button>

      <div style={{ display: 'flex', justifyContent: 'flex-end', padding: '1rem', border: '1px solid #ccc' }}>
        <MagicBellProvider
          apiKey={config.apiKey}
          userEmail={config.userEmail}
          userKey={config.userJwt}
        >
          <FloatingInbox tabs={tabs} />
        </MagicBellProvider>
      </div>
    </div>
  );
}

